INSERT INTO public.vocabulary_examples (id, vocab_id, japanese, reading, translation) VALUES
('ex_n4_auto_1', 'v_n4_auto_1', '友達にプレゼントを送りました。', 'ともだち に プレゼント を おくりました。', 'Saya telah mengirim hadiah kepada teman.'),
('ex_n4_auto_2', 'v_n4_auto_2', '失くした鍵を探しています。', 'なくした かぎ を さがしています。', 'Saya sedang mencari kunci yang hilang.'),
('ex_n4_auto_3', 'v_n4_auto_3', '急げば電車に間に合います。', 'いそげば でんしゃ に まにあいます。', 'Jika bergegas, kita akan sempat naik kereta.'),
('ex_n4_auto_4', 'v_n4_auto_4', '道で財布を拾いました。', 'みち で さいふ を ひろいました。', 'Saya memungut dompet di jalan.'),
('ex_n4_auto_5', 'v_n4_auto_5', '毎日電車で大学に通っています。', 'まいにち でんしゃ で だいがく に かよっています。', 'Setiap hari saya pulang pergi kuliah naik kereta.'),
('ex_n4_auto_6', 'v_n4_auto_6', 'みんなで盆踊りを踊りましょう。', 'みんな で ぼんおどり を おどりましょう。', 'Mari kita menari tarian Bon bersama.'),
('ex_n4_auto_7', 'v_n4_auto_7', 'ご飯はよく噛んで食べてください。', 'ごはん は よく かんで たべて ください。', 'Makanlah nasi dengan mengunyahnya baik-baik.'),
('ex_n4_auto_8', 'v_n4_auto_8', 'たくさんの中から好きなものを選んでください。', 'たくさん の なか から すきな もの を えらんで ください。', 'Pilihlah yang Anda sukai dari sekian banyak pilihan.'),
('ex_n4_auto_9', 'v_n4_auto_9', '友達を映画に誘いました。', 'ともだち を えいが に さそいました。', 'Saya mengajak teman menonton film.'),
('ex_n4_auto_10', 'v_n4_auto_10', '明日、朝六時に起こしてください。', 'あした、あさ ろくじ に おこして ください。', 'Tolong bangunkan saya besok jam 6 pagi.'),
('ex_n4_auto_11', 'v_n4_auto_11', '彼は納得した様子でうなずきました。', 'かれ は なっとく した ようす で うなずきました。', 'Dia mengangguk seolah mengerti/setuju.'),
('ex_n4_auto_12', 'v_n4_auto_12', '先生を怒らせてしまいました。', 'せんせい を おこらせて しまいました。', 'Saya tidak sengaja membuat guru marah.'),
('ex_n4_auto_13', 'v_n4_auto_13', '今日は私が昼ご飯をおごりましょう。', 'きょう は わたし が ひるごはん を おごりましょう。', 'Hari ini biar saya yang traktir makan siang.'),
('ex_n4_auto_14', 'v_n4_auto_14', '母の料理を手伝います。', 'はは の りょうり を てつだいます。', 'Saya membantu ibu memasak.'),
('ex_n4_auto_15', 'v_n4_auto_15', 'レジでお金を払いました。', 'レジ で おかね を はらいました。', 'Saya membayar uang di kasir.'),
('ex_n4_auto_16', 'v_n4_auto_16', '彼女はいつも楽しそうに笑います。', 'かのじょ は いつも たのしそう に わらいます。', 'Dia selalu tertawa dengan tampak senang.'),
('ex_n4_auto_17', 'v_n4_auto_17', '泥棒が警察に捕まりました。', 'どろぼう が けいさつ に つかまりました。', 'Pencuri ditangkap oleh polisi.'),
('ex_n4_auto_18', 'v_n4_auto_18', '今、駅に向かっています。', 'いま、えき に むかっています。', 'Sekarang saya sedang menuju ke stasiun.'),
('ex_n4_auto_19', 'v_n4_auto_19', '風邪が弟にうつってしまいました。', 'かぜ が おとうと に うつって しまいました。', 'Penyakit flu menular ke adik laki-laki saya.'),
('ex_n4_auto_20', 'v_n4_auto_20', '洗濯物が太陽の光で乾きました。', 'せんたくもの が たいよう の ひかり で かわきました。', 'Cucian sudah kering karena sinar matahari.'),
('ex_n4_auto_21', 'v_n4_auto_21', 'ドライヤーを使って髪を乾かします。', 'ドライヤー を つかって かみ を かわかします。', 'Mengeringkan rambut menggunakan hair dryer.'),
('ex_n4_auto_22', 'v_n4_auto_22', 'この試験は難しいと思います。', 'この しけん は むずかしい と おもいます。', 'Saya pikir ujian ini sulit.'),
